import { useState } from "react";
import { motion, AnimatePresence } from "framer-motion";

const PLANS = [
  {
    name: "Starter",
    monthly: "₹4,999",
    annual: "₹3,999",
    desc: "Perfect for solopreneurs and small businesses.",
    highlight: false,
    features: ["5-page website", "Mobile responsive", "Contact form", "1 month support", "Basic SEO setup"],
  },
  {
    name: "Pro",
    monthly: "₹9,999",
    annual: "₹7,999",
    desc: "Ideal for growing businesses and brands.",
    highlight: true,
    features: ["Up to 15 pages", "Custom animations", "CMS integration", "3 months support", "Advanced SEO", "Analytics setup"],
  },
  {
    name: "Enterprise",
    monthly: "₹19,999",
    annual: "₹15,999",
    desc: "For complex projects that need everything.",
    highlight: false,
    features: ["Unlimited pages", "Custom web app", "E-commerce ready", "6 months support", "Priority delivery", "Dedicated manager"],
  },
];

export default function Pricing() {
  const [annual, setAnnual] = useState(false);

  return (
    <section id="pricing" className="py-24 px-8 md:px-16 bg-[#0c0c0c]">
      {/* Header */}
      <div className="text-center mb-16">
        <p className="text-[#C8FF00] text-[10px] tracking-[0.5em] uppercase mb-4">Investment</p>
        <h2 style={{ fontFamily: "'Bebas Neue', sans-serif" }} className="text-6xl md:text-7xl leading-none mb-10">
          Pricing Plans
        </h2>
        <div className="inline-flex border border-white/8 p-1 rounded-full">
          {[
            ["Monthly", false],
            ["Annual · Save 20%", true],
          ].map(([label, val]) => (
            <button
              key={label}
              onClick={() => setAnnual(val)}
              className={`px-6 py-2.5 rounded-full text-xs font-medium tracking-widest uppercase transition-all duration-300 ${
                annual === val ? "bg-[#C8FF00] text-black font-bold" : "text-gray-500 hover:text-gray-300"
              }`}
            >
              {label}
            </button>
          ))}
        </div>
      </div>

      {/* Plans Grid */}
      <div className="grid md:grid-cols-3 gap-5 max-w-5xl mx-auto">
        {PLANS.map((p, i) => (
          <motion.div
            key={i}
            whileHover={{ y: -6 }}
            transition={{ type: "spring", stiffness: 300, damping: 20 }}
            className={`relative p-8 overflow-hidden ${
              p.highlight ? "bg-[#C8FF00] text-black" : "bg-[#111] border border-white/5"
            }`}
          >
            {/* Most Popular Label */}
            {p.highlight && (
              <>
                <div className="absolute top-0 left-0 right-0 h-[2px] bg-black" />
                <span className="absolute -top-[1px] left-1/2 -translate-x-1/2 bg-black text-[#C8FF00] text-[9px] px-4 py-1 tracking-[0.3em] uppercase">
                  Most Popular
                </span>
              </>
            )}

            <h3
              className={`text-xs font-bold tracking-[0.35em] uppercase mb-2 ${
                p.highlight ? "text-black/60" : "text-gray-500"
              }`}
            >
              {p.name}
            </h3>

            {/* Price AnimatePresence */}
            <AnimatePresence mode="wait">
              <motion.div
                key={annual ? "annual" : "monthly"}
                initial={{ opacity: 0, y: 10 }}
                animate={{ opacity: 1, y: 0 }}
                exit={{ opacity: 0, y: -10 }}
                transition={{ duration: 0.3 }}
                className={`text-4xl md:text-5xl font-bold ${p.highlight ? "text-black" : "text-white"} my-4`}
              >
                {annual ? p.annual : p.monthly}
              </motion.div>
            </AnimatePresence>

            <p className={`text-sm mb-4 ${p.highlight ? "text-black/70" : "text-gray-400"}`}>{p.desc}</p>

            {/* Features */}
            <ul className="space-y-2 mb-6">
              {p.features.map((f, idx) => (
                <li key={idx} className={`text-xs ${p.highlight ? "text-black/70" : "text-gray-400"}`}>
                  • {f}
                </li>
              ))}
            </ul>

            <motion.a
              href="#contact"
              whileHover={{ scale: 1.03 }}
              whileTap={{ scale: 0.97 }}
              className={`inline-block px-6 py-3 text-xs font-bold tracking-[0.25em] uppercase ${
                p.highlight ? "bg-black text-[#C8FF00]" : "bg-[#C8FF00] text-black"
              }`}
            >
              Start Project →
            </motion.a>
          </motion.div>
        ))}
      </div>
    </section>
  );
}
